SELECT 
FROM job_info


        AND app_code = #{request.appCode}


        AND job_name LIKE CONCAT('%', #{request.jobName}, '%')


        AND handler_name LIKE CONCAT('%', #{request.handlerName}, '%')


        AND schedule_type = #{request.scheduleType}


        AND status = #{request.status}


ORDER BY update_time DESC

    LIMIT #{request.size} OFFSET ${(request.current - 1) * request.size}

SELECT COUNT(*)
FROM job_info


        AND app_code = #{request.appCode}


        AND job_name LIKE CONCAT('%', #{request.jobName}, '%')


        AND handler_name LIKE CONCAT('%', #{request.handlerName}, '%')


        AND schedule_type = #{request.scheduleType}


        AND status = #{request.status}
